import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.Codec;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureXSSExample {

    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        Codec codec = ESAPI.encoder();

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Sanitize and encode user input before displaying
            String safeUserInput = codec.encodeForHTML(userInput);

            System.out.println("Hello, " + safeUserInput + "!");

        } catch (IOException e) {
            System.err.println("Error reading input");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
